import{c as e,Q as n,j as a,m as o}from"./chunks/framework.DpF7k2f3.js";const g=JSON.parse('{"title":"Chapter 5: LLM API & Prompt Engineering","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en/part2-fundamentals/chapter5.md","filePath":"en/part2-fundamentals/chapter5.md"}'),r={name:"en/part2-fundamentals/chapter5.md"};function i(l,t,s,h,p,c){return n(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="chapter-5-llm-api-prompt-engineering" tabindex="-1">Chapter 5: LLM API &amp; Prompt Engineering <a class="header-anchor" href="#chapter-5-llm-api-prompt-engineering" aria-label="Permalink to &quot;Chapter 5: LLM API &amp; Prompt Engineering&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>Congratulations! You&#39;re finally getting to the real stuff!</p><p>In previous chapters, we talked about a lot of &quot;abstract&quot; things—industry cognition, entry roadmap, engineering basics. Starting from this chapter, we&#39;re entering the ** hardcore area** of AI application development.</p><p>This chapter is one of the most core technical chapters in the book. The original version taught some basic techniques, but honestly, it was a bit shallow—like teaching you &quot;how to use chopsticks&quot; but not telling you &quot;how to pick up rolling meatballs.&quot; I&#39;ll supplement these truly useful things from real practice.</p><p>After reading this chapter, you will take away:</p><ul><li><strong>Rock-solid API calls</strong>: Not just making them work, but handling high concurrency, streaming output, and graceful degradation when models fail</li><li><strong>Systematic Prompt methodology</strong>: Not memorizing tricks, but understanding why certain approaches work and when to use which technique</li><li><strong>Production-grade structured output</strong>: JSON Schema, multi-level nesting, information extraction pipelines</li><li><strong>Smart context management</strong>: Conversation state machines, intent recognition, slot filling</li><li><strong>Real cost control</strong>: Not theory, but experience of burning through money and cutting it in half</li><li><strong>Lessons learned from踩坑</strong>: Pits I&#39;ve fallen into, so you don&#39;t have to</li></ul><hr><blockquote><p><strong>Full translation coming soon. You can read the Chinese version in the meantime.</strong></p><p>中文原文：<a href="/jumpstart-ai/zh/part2-fundamentals/chapter5.html">阅读中文版</a></p></blockquote>',9)])])}const m=e(r,[["render",i]]);export{g as __pageData,m as default};
